const input = $input.first().json;

const prompt = `Na podstawie poniższej kondensacji tygodnia wyodrębnij ponadczasowe informacje.

Wyodrębnij (tylko to co naprawdę ponadczasowe, pomiń codzienne drobiazgi):
- Kluczowe osoby: imiona, role, relacje (category: person)
- Projekty i technologie: nazwy, kontekst (category: project)
- Wnioski i obserwacje: lekcje, wzorce, decyzje (category: insight)

Zwróć TYLKO JSON, bez markdown, bez dodatkowego tekstu:
{"insights": [{"category": "insight|person|project", "content": "..."}]}

Kondensacja tygodnia:
${input.weekly_condensation_text}`;

return [{ json: { user_id: input.user_id, prompt_text: prompt } }];

const userId = $('Workflow Input').first().json.user_id;
const llmResponse = $input.first().json.text || $input.first().json.output || '';

// Strip markdown code blocks if model wrapped JSON in them
const cleaned = llmResponse
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    return [{ json: { error: 'Failed to parse insights', raw: llmResponse } }];
  }
}

const insights = parsed.insights || [];
if (insights.length === 0) return [];

return insights.map(insight => ({
  json: {
    pageContent: insight.content,
    metadata: {
      category: insight.category,
      user_id: userId
    }
  }
}));
